function norm(s) {
  return (s || "")
    .normalize("NFKC")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
}

function teamNameOf(t) {
  return t?.team_name ?? t?.nameCrew ?? t?.name ?? "";
}

const src = $("Edit Fields2").first().json || {};

const unavailableSet = new Set(
  (src.UnavailableTeams || []).map(u =>
    norm(u?.team_name ?? u?.nameCrew ?? u?.name)
  )
);

const allTeams = Array.isArray(src.Teams) ? src.Teams : [];

const filteredTeams = allTeams.filter(t =>
  !unavailableSet.has(norm(teamNameOf(t)))
);

const excludedTeams = allTeams.filter(t =>
  unavailableSet.has(norm(teamNameOf(t)))
);

return [
  {
    json: {
      Teams: filteredTeams,
      ExcludedTeams: excludedTeams
    }
  }
];

// --- helpers ---
function isEmptyStr(s){ 
  return typeof s !== "string" || s.trim().length === 0; 
}
function toNum(x){ const n = Number(x); return Number.isFinite(n) ? n : 0; }
function toNumOrNull(x){ const n = Number(x); return Number.isFinite(n) ? n : null; }
function normKey(s){ return String(s||"").normalize("NFKC").replace(/\s+/g," ").trim().toLowerCase(); }
function cleanStr(s){ return String(s||"").normalize("NFKC").replace(/\s+/g," ").trim(); }

// универсальный геттер полей команды (поддерживает оба набора ключей)
function teamMeta(team){
  if (!team || typeof team !== "object") return {
    team_id: null, team_name: (typeof team==="string"? cleanStr(team) : null),
    airtable_id: null, address: null, latitude: null, longitude: null
  };
  const team_id     = team.id ?? team.team_id ?? null;
  const team_name   = cleanStr(team.name ?? team.team_name ?? "");
  const airtable_id = team.airtable_id ?? team.team_airtable_id ?? null;
  const team_address     = team.address ?? team.team_address ?? null;
  const latitude    = toNumOrNull(team.latitude ?? team.team_latitude ?? team.lat);
  const longitude   = toNumOrNull(team.longitude ?? team.team_longitude ?? team.lon);
  return { team_id, team_name, airtable_id, team_address, latitude, longitude };
}

// корректное определение "назначена ли команда"
function hasTeam(team){
  if (!team) return false;
  if (typeof team === "string") return !isEmptyStr(team);
  const m = teamMeta(team);
  return !!(m.team_id || m.team_name || m.airtable_id);
}

// нормализация scheduled_time только для веса сортировки
function normalizeScheduledTimeLike(t){
  const st = t?.scheduled_time;
  if (st && typeof st === "object") return st;
  const exact   = t?.exact_time ?? t?.appointment_time ?? t?.start_time ?? null;
  const tfStart = t?.timeframe_start ?? t?.window_start ?? t?.start_window ?? null;
  const tfEnd   = t?.timeframe_end   ?? t?.window_end   ?? t?.end_window   ?? null;
  if (exact) return { type: "exact", start: String(exact) };
  if (tfStart || tfEnd) return { type: "timeframe", start: tfStart ? String(tfStart) : null, end: tfEnd ? String(tfEnd) : null };
  return null;
}
function timeWeightFromTask(t){
  const st = normalizeScheduledTimeLike(t);
  if (!st || typeof st !== "object") return 3;
  if (st.type === "exact") return 0;
  if (st.type === "timeframe") return 1;
  return 2;
}

// --- input ---
const tasks = Array.isArray($('Edit Fields2').first().json.tasks)
  ? $('Edit Fields2').first().json.tasks
  : [];

// --- split assigned / unassigned ---
const assigned = [];
const unassigned = [];
for (const t of tasks) (hasTeam(t.team) ? assigned : unassigned).push(t);

// --- durations summary ---
function hoursOf(arr){ return arr.reduce((s,t)=> s + toNum(t.estimated_duration ?? t.duration), 0); }
const total_hours = hoursOf(tasks);
const assigned_hours = hoursOf(assigned);
const unassigned_hours = hoursOf(unassigned);

// --- group assigned by team ---
const byTeam = new Map();
for (const t of assigned){
  const meta = teamMeta(t.team);
  const teamKey = meta.team_id ? `id:${normKey(meta.team_id)}` : `name:${normKey(meta.team_name)}`;
  if (!byTeam.has(teamKey)){
    byTeam.set(teamKey, { ...meta, tasks: [], totals: { estimated_hours: 0, task_count: 0 } });
  }
  const entry = byTeam.get(teamKey);
  entry.tasks.push(t);
  entry.totals.estimated_hours += toNum(t.estimated_duration ?? t.duration);
  entry.totals.task_count += 1;
}

// сортировка задач внутри команды
for (const v of byTeam.values()){
  v.tasks.sort((a,b)=>{
    const tw = timeWeightFromTask(a) - timeWeightFromTask(b);
    if (tw !== 0) return tw;
    const ap = (b.priority||0) - (a.priority||0);
    if (ap !== 0) return ap;
    return (toNum(a.estimated_duration ?? a.duration)) - (toNum(b.estimated_duration ?? b.duration));
  });
}

const assigned_by_team = Array.from(byTeam.values())
  .sort((a,b)=> (a.team_name||"").localeCompare(b.team_name||""));

// --- return ---
return [{
  json: {
    unassigned,
    assigned,
    counts: { total: tasks.length, assigned: assigned.length, unassigned: unassigned.length },
    durations: { total_hours, assigned_hours, unassigned_hours },
    assigned_by_team
  }
}];

// === MATCHER: задача ↔ команда по скиллам, с учётом УРОВНЯ (level 1 = высший) ===
function normSkillName(s) {
  return String(s || "").normalize("NFKC").replace(/\s+/g, " ").trim()
    .replace(/\s*-\s*\d+$/, "").toLowerCase(); // срезаем "- N" для сравнения по имени
}
function normText(s) { return String(s || "").normalize("NFKC").replace(/\s+/g, " ").trim(); }
function toNumOrNull(x) {
  if (x === null || x === undefined || x === "") return null;
  const n = Number(x); return Number.isFinite(n) ? n : null;
}
// скилл может прийти как {name, level} (новый фронт) или "Name - 2" (старый) → {name, level}
function parseTeamSkill(s) {
  if (s && typeof s === "object") {
    const lvl = toNumOrNull(s.level);
    const m = String(s.name || "").match(/-\s*(\d+)\s*$/); // уровень мог остаться в имени
    return { name: normSkillName(s.name), level: lvl != null ? lvl : (m ? Number(m[1]) : null) };
  }
  const raw = String(s || ""); const m = raw.match(/-\s*(\d+)\s*$/);
  return { name: normSkillName(raw), level: m ? Number(m[1]) : null };
}

const src = ($input.first()?.json) || {};
const tasks = Array.isArray(src.tasks_with_skills) ? src.tasks_with_skills
  : (Array.isArray(src["unassigned tasks"]) ? src["unassigned tasks"] : []);
const available_teams = Array.isArray(src.available_teams) ? src.available_teams
  : (Array.isArray(src.Teams) ? src.Teams : []);

const teamSkillMap = available_teams.map(t => {
  const team_name = normText(t.team_name ?? t.nameCrew ?? t.name ?? "");
  const address   = t.team_address ?? t.address ?? "";
  const latitude  = toNumOrNull(t.team_latitude ?? t.latitude ?? t.lat);
  const longitude = toNumOrNull(t.team_longitude ?? t.longitude ?? t.lon);
  const skillLevels = new Map(); // нормализованное имя -> лучший (минимальный) уровень
  for (const sk of (t.skills || [])) {
    const { name, level } = parseTeamSkill(sk);
    if (!name) continue;
    if (!skillLevels.has(name)) skillLevels.set(name, level);
    else { const prev = skillLevels.get(name); if (level != null && (prev == null || level < prev)) skillLevels.set(name, level); }
  }
  return { name: team_name, team_name, address, latitude, longitude, skillLevels, raw: t };
});

const taskReqCache = new Map();
function requiredSkillsOfTask(task) {
  if (taskReqCache.has(task)) return taskReqCache.get(task);
  const required = (task.skills || []).map(s => normSkillName(s?.name ?? s)).filter(Boolean);
  taskReqCache.set(task, required); return required;
}
function canTeamDoTask(team, task) {
  const required = requiredSkillsOfTask(task);
  if (!required.length) return false;
  return required.every(r => team.skillLevels.has(r));
}
// эффективный уровень команды для задачи = худший (макс. номер) среди требуемых скиллов
function teamLevelForTask(team, task) {
  let worst = null;
  for (const r of requiredSkillsOfTask(task)) {
    const lv = team.skillLevels.get(r);
    if (lv == null) continue;
    worst = (worst == null) ? lv : Math.max(worst, lv);
  }
  return worst; // null = уровень неизвестен
}
function pickTaskGeo(t) {
  const p = t.project || {};
  return { address: p.project_address ?? p.address ?? t.address ?? null,
    latitude: toNumOrNull(p.project_latitude ?? t.latitude),
    longitude: toNumOrNull(p.project_longitude ?? t.longitude) };
}
function findEligibleTeams(task) {
  const matches = [];
  for (const team of teamSkillMap) {
    if (canTeamDoTask(team, task)) matches.push({
      optional_team_name: team.name, optional_team_address: team.address,
      optional_teamlatitude: team.latitude, optional_team_longitude: team.longitude,
      optional_team_level: teamLevelForTask(team, task), // 1 = высший приоритет
    });
  }
  return matches.sort((a, b) => { // уровень 1 первым, null в конец, затем по имени
    const la = a.optional_team_level == null ? Infinity : a.optional_team_level;
    const lb = b.optional_team_level == null ? Infinity : b.optional_team_level;
    if (la !== lb) return la - lb;
    return normText(a.optional_team_name).localeCompare(normText(b.optional_team_name));
  });
}
function findEligibleTasks(team) {
  const matches = [];
  for (const t of tasks) {
    if (canTeamDoTask(team, t)) {
      const geo = pickTaskGeo(t); const firstLine = String(t.description || "").split("\n")[0] || "";
      matches.push({
        optional_task_id: t.id ?? t.project?.id ?? null,
        optional_task_title: t.title ?? t["Task Title"] ?? normText(firstLine),
        optional_task_address: geo.address, optional_task_latitude: geo.latitude,
        optional_task_longitude: geo.longitude, optional_task_priority: t.priority ?? t.Priority ?? null,
        optional_task_duration: t.estimated_duration ?? t.duration ?? t.Duration ?? null,
        optional_task_level: teamLevelForTask(team, t),
      });
    }
  }
  return matches.sort((a, b) => normText(a.optional_task_title ?? "").localeCompare(normText(b.optional_task_title ?? "")));
}

const tasks_with_optional_teams = tasks.map(t => ({ ...t, optional_team: findEligibleTeams(t) }));
const teams_with_optional_tasks = teamSkillMap.map(team => ({
  name: team.name, address: team.address, latitude: team.latitude, longitude: team.longitude,
  optional_tasks: findEligibleTasks(team),
})).sort((a, b) => normText(a.name).localeCompare(normText(b.name)));

return [{ json: { tasks_with_optional_teams, teams_with_optional_tasks } }];

// helper: безопасное клонирование JSON-структур
const clone = (o) => JSON.parse(JSON.stringify(o));

const main = clone($input.first().json);
main.output = main.output ?? {};

// --- comments из первого агента (ИМЯ ДОЛЖНО СОВПАДАТЬ!) ---
let comments1 = {};
try {
  const items1 = $items('Assigned tasks Agent', 0, 0) || []; 
  const c1 = items1[0]?.json?.output?.comments;
  comments1 = (c1 && typeof c1 === 'object' && !Array.isArray(c1)) ? c1 : {};
} catch (e) {
  comments1 = {};
}

// --- comments из второго агента (это текущий вход) ---
const c2 = main.output?.comments;
const comments2 = (c2 && typeof c2 === 'object' && !Array.isArray(c2)) ? c2 : {};

// --- складываем отдельно ---
main.output['commentsAI-1'] = comments1;
main.output['commentsAI-2'] = comments2;

// (опционально) убрать старый output.comments, чтобы не путал downstream-схемы
delete main.output.comments;

// вернуть обновлённый первый + остальные входные, чтобы их не потерять
const rest = $input.all().slice(1);
return [{ json: main }, ...rest];

